(function(){function mount(){if(document.getElementById('kimi-emblem'))return;if(!document.body||!document.querySelector('.monaco-workbench')){setTimeout(mount,400);return;}
var st=document.createElement('style');st.textContent="#kimi-emblem{position:fixed;left:30px;top:300px;z-index:99997;width:92px;height:92px;cursor:grab;user-select:none;-webkit-user-select:none;animation:keb 5s ease-in-out infinite;}#kimi-emblem.ke-drag{cursor:grabbing;animation:none;}#kimi-emblem img{width:100%;height:100%;object-fit:contain;filter:drop-shadow(0 0 8px #c19a5577);-webkit-user-drag:none;pointer-events:none;}@keyframes keb{0%,100%{transform:scale(1)}50%{transform:scale(1.055)}}";document.head.appendChild(st);
var el=document.createElement('div');el.id='kimi-emblem';el.innerHTML='<img src="data:image/png;base64,">';document.body.appendChild(el);
function place(l,t){el.style.left=Math.max(0,Math.min(window.innerWidth-el.offsetWidth,l))+'px';el.style.top=Math.max(0,Math.min(window.innerHeight-el.offsetHeight,t))+'px';el.style.right='auto';el.style.bottom='auto';}
try{var s=JSON.parse(localStorage.getItem('kimiEmblemPos2')||'null');if(s&&typeof s.left==='number')place(s.left,s.top);}catch(e){}
var dg=false,mv=0,sx=0,sy=0,ox=0,oy=0;el.addEventListener('mousedown',function(e){if(e.button!==0)return;var r=el.getBoundingClientRect();dg=true;mv=0;sx=e.clientX;sy=e.clientY;ox=r.left;oy=r.top;el.classList.add('ke-drag');e.preventDefault();});
window.addEventListener('mousemove',function(e){if(!dg)return;var dx=e.clientX-sx,dy=e.clientY-sy;mv=Math.max(mv,Math.abs(dx)+Math.abs(dy));place(ox+dx,oy+dy);});
window.addEventListener('mouseup',function(){if(!dg)return;dg=false;el.classList.remove('ke-drag');if(mv>=4){var r=el.getBoundingClientRect();try{localStorage.setItem('kimiEmblemPos2',JSON.stringify({left:r.left,top:r.top}));}catch(e){}}});}
setTimeout(mount,520);})();